// main.dart
import 'package:flutter/material.dart';
import 'package:flutter_dotenv/flutter_dotenv.dart';
import 'package:image_picker/image_picker.dart';
import 'package:http/http.dart' as http;
import 'package:amazon_s3_cognito/amazon_s3_cognito.dart';
import 'dart:convert';
import 'dart:io';

Future<void> main() async {
  await dotenv.load(fileName: ".env");
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Photo Analyzer',
      theme: ThemeData(primarySwatch: Colors.blue),
      home: PhotoUploadScreen(),
    );
  }
}

class PhotoUploadScreen extends StatefulWidget {
  @override
  _PhotoUploadScreenState createState() => _PhotoUploadScreenState();
}

class _PhotoUploadScreenState extends State<PhotoUploadScreen> {
  final ImagePicker _picker = ImagePicker();
  File? _selectedImage;
  String _analysisResult = '';
  bool _isLoading = false;

  Future<void> _pickImage() async {
    final XFile? image = await _picker.pickImage(source: ImageSource.gallery);
    if (image != null) {
      setState(() {
        _selectedImage = File(image.path);
        _analysisResult = '';
      });
    }
  }

  Future<void> _uploadAndAnalyze() async {
    if (_selectedImage == null) return;

    setState(() => _isLoading = true);

    try {
      final s3Url = await _uploadToS3(_selectedImage!);
      final analysis = await _analyzeWithVision(_selectedImage!);
      
      setState(() {
        _analysisResult = 'Upload successful!\nURL: $s3Url\n\nAnalysis:\n$analysis';
        _isLoading = false;
      });
    } catch (e) {
      setState(() {
        _analysisResult = 'Error: $e';
        _isLoading = false;
      });
    }
  }

  Future<String> _uploadToS3(File file) async {
    final awsAccessKey = dotenv.env['AWS_ACCESS_KEY'];
    final awsSecretKey = dotenv.env['AWS_SECRET_KEY'];
    final bucketName = dotenv.env['AWS_BUCKET_NAME'];
    final region = dotenv.env['AWS_REGION'] ?? 'us-east-1';

    String fileName = 'uploads/${DateTime.now().millisecondsSinceEpoch}.jpg';
    
    await AmazonS3Cognito.upload(
      file.path,
      bucketName!,
      fileName,
      awsAccessKey!,
      awsSecretKey!,
      region,
    );

    return 'https://$bucketName.s3.$region.amazonaws.com/$fileName';
  }

  Future<String> _analyzeWithVision(File file) async {
    final apiKey = dotenv.env['GOOGLE_CLOUD_API_KEY'];
    final bytes = await file.readAsBytes();
    final base64Image = base64Encode(bytes);

    final response = await http.post(
      Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$apiKey'),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({
        'requests': [
          {
            'image': {'content': base64Image},
            'features': [
              {'type': 'LABEL_DETECTION', 'maxResults': 5},
              {'type': 'FACE_DETECTION', 'maxResults': 5},
            ]
          }
        ]
      }),
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      final labels = data['responses'][0]['labelAnnotations'] as List? ?? [];
      return labels.map((l) => '${l['description']} (${(l['score'] * 100).toStringAsFixed(1)}%)').join('\n');
    } else {
      throw Exception('Vision API error: ${response.body}');
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Photo Analyzer')),
      body: Padding(
        padding: EdgeInsets.all(16),
        child: Column(
          children: [
            if (_selectedImage != null)
              Image.file(_selectedImage!, height: 300),
            SizedBox(height: 20),
            ElevatedButton.icon(
              onPressed: _pickImage,
              icon: Icon(Icons.photo_library),
              label: Text('Select Photo'),
            ),
            SizedBox(height: 10),
            ElevatedButton.icon(
              onPressed: _selectedImage != null && !_isLoading ? _uploadAndAnalyze : null,
              icon: _isLoading ? SizedBox(width: 20, height: 20, child: CircularProgressIndicator(strokeWidth: 2)) : Icon(Icons.cloud_upload),
              label: Text('Upload & Analyze'),
            ),
            SizedBox(height: 20),
            Expanded(
              child: SingleChildScrollView(
                child: Text(_analysisResult),
              ),
            ),
          ],
        ),
      ),
    );
  }
}